// Extract Fireflies webhook data
const payload = $input.first().json;

// Fireflies webhook sends different formats — normalize
const data = {
  fireflies_id: payload.meetingId || payload.id,
  title: payload.title || payload.meetingTitle || '',
  transcript_text: payload.transcript || payload.sentences?.map(s => `${s.speaker_name}: ${s.text}`).join('\n') || '',
  summary: payload.summary || payload.action_items || '',
  duration_minutes: payload.duration ? Math.round(payload.duration / 60) : null,
  participants: payload.participants || payload.attendees || [],
  date: payload.date || payload.dateString || new Date().toISOString(),
  platform: payload.meeting_source || 'google_meet'
};

// Find external participants (not @guardline.io)
const externalParticipants = data.participants.filter(
  p => !(p.email || p).includes('guardline')
);

return [{ json: { ...data, external_participants: externalParticipants } }];

// Identify which team member was in the meeting
const extracted = $('Extract Fireflies Data').first().json;
const members = $('Get Team Members').all().map(m => m.json);
const lead = $('Find Lead by Email').first()?.json || {};

const participants = extracted.participants.map(p => (p.email || p || '').toLowerCase());
const assignedMember = members.find(m =>
  participants.includes(m.email.toLowerCase())
) || members.find(m => m.id === lead.owner_id) || members[0];

return [{ json: { extracted, lead, member: assignedMember } }];

