// Parse Claude analysis
const raw = $('Claude — Analyze Meeting').first().json;
let analysis;
try {
  const text = typeof raw === 'string' ? raw : (raw.text || raw.content || JSON.stringify(raw));
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch (e) {
  analysis = {
    summary: ['Erro ao processar transcrição'],
    next_steps: [],
    deal_signal: 'neutral',
    deal_signal_reason: 'Erro na análise',
    objections: [],
    unanswered_questions: [],
    recommended_next_contact: { timing: 'em 3 dias', channel: 'email', suggested_message_angle: 'Follow-up geral' },
    close_probability_delta: 0,
    julio_recommendation: 'Revisar transcrição manualmente'
  };
}

const prev = $('Identify Member & Lead').first().json;
return [{ json: { analysis, ...prev } }];

// Build Slack notification
const d = $('Parse Analysis').first().json;
const analysis = d.analysis;

const signalEmoji = {
  strong_buy: '🟢',
  interested: '🟡',
  neutral: '⚪',
  risk: '🟠',
  lost: '🔴'
};

const message = `${signalEmoji[analysis.deal_signal] || '⚪'} *Reunião analisada: ${d.lead.company_name || d.extracted.title}*\n\n*Resumo:*\n${analysis.summary.map((b, i) => `${i+1}. ${b}`).join('\n')}\n\n*Próximos passos:*\n${analysis.next_steps.map(s => `→ ${s.action} (${s.responsible}) — ${s.deadline}`).join('\n')}\n\n*Deal Signal:* ${(analysis.deal_signal || '').toUpperCase()} — ${analysis.deal_signal_reason}\n\n*Julio recomenda:* _${analysis.julio_recommendation}_\n\n_Follow-up automático será enviado em ${analysis.recommended_next_contact.timing} via ${analysis.recommended_next_contact.channel}_`;

return [{ json: { message, member_name: d.member.name } }];
